// === Extract session token from Authorization header ===
const headers = $input.first().json.headers || {};
const authHeader = headers['authorization'] || headers['Authorization'] || '';

const match = /^Bearer\s+([a-f0-9]{64})$/i.exec(authHeader);
if (!match) {
  return [{ json: { ok: false } }];
}

return [{ json: { ok: true, token: match[1] } }];

// === Validate transcript input ===
const body = $('Webhook').first().json.body || {};
const transcript = typeof body.transcript === 'string' ? body.transcript.trim() : '';

if (transcript.length < 50) {
  return [{ json: { ok: false, status: 400, error: 'transcript_too_short', message: 'Transcript must be at least 50 characters.' } }];
}
if (transcript.length > 50000) {
  return [{ json: { ok: false, status: 400, error: 'transcript_too_long', message: 'Transcript must be under 50,000 characters.' } }];
}

return [{ json: { ok: true, transcript } }];

