{
  "model": "gpt-4o-mini",
  "messages": [
    {
      "role": "system",
      "content": "You are an AI assistant that converts meeting transcripts into structured debriefs. Rules:\n- NEVER invent people. If an owner of an action item is not clearly mentioned by name in the transcript, set owner to null.\n- Extract action items even from implicit commitments (e.g. 'I will look into that').\n- The follow-up email is written from the meeting attendee's first-person perspective, addressed to the other participants, ~120-180 words, professional tone, no signature placeholder. It should confirm what was decided and list what happens next.\n- The summary is 2-3 sentences capturing the essence of the meeting.\n- If the input clearly is not a meeting (too short to extract anything meaningful, unrelated text like a recipe or poem), set isValidMeeting to false and return empty strings/arrays for the other fields.\n- meetingDate should be an ISO date (YYYY-MM-DD) if mentioned in the transcript, otherwise null."
    },
    {
      "role": "user",
      "content": {{ JSON.stringify($json.transcript) }}
    }
  ],
  "response_format": {
    "type": "json_schema",
    "json_schema": {
      "name": "meeting_debrief",
      "strict": true,
      "schema": {
        "type": "object",
        "properties": {
          "isValidMeeting": { "type": "boolean" },
          "title": { "type": ["string", "null"] },
          "meetingDate": { "type": ["string", "null"] },
          "summary": { "type": ["string", "null"] },
          "participants": { "type": "array", "items": { "type": "string" } },
          "decisions": { "type": "array", "items": { "type": "string" } },
          "actionItems": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "text": { "type": "string" },
                "owner": { "type": ["string", "null"] }
              },
              "required": ["text", "owner"],
              "additionalProperties": false
            }
          },
          "blockers": { "type": "array", "items": { "type": "string" } },
          "followupEmail": { "type": ["string", "null"] }
        },
        "required": ["isValidMeeting", "title", "meetingDate", "summary", "participants", "decisions", "actionItems", "blockers", "followupEmail"],
        "additionalProperties": false
      }
    }
  },
  "temperature": 0.2
}

parameters.jsCode:
// === Parse OpenAI response & extract structured draft ===
const response = $input.first().json;

try {
  const choice = response.choices && response.choices[0];
  if (!choice || !choice.message || !choice.message.content) {
    return [{ json: { ok: false, status: 502, error: 'llm_failed', message: 'OpenAI returned no content.' } }];
  }

  const draft = JSON.parse(choice.message.content);

  if (draft.isValidMeeting === false) {
    return [{
      json: {
        ok: true,
        isValidMeeting: false,
        message: "This doesn't look like a meeting transcript. Try pasting longer notes or a transcript with more context."
      }
    }];
  }

  return [{
    json: {
      ok: true,
      isValidMeeting: true,
      draft: {
        title: draft.title || 'Untitled Meeting',
        meetingDate: draft.meetingDate,
        summary: draft.summary || '',
        participants: draft.participants || [],
        decisions: draft.decisions || [],
        actionItems: draft.actionItems || [],
        blockers: draft.blockers || [],
        followupEmail: draft.followupEmail || ''
      }
    }
  }];
} catch (err) {
  return [{ json: { ok: false, status: 502, error: 'llm_failed', message: 'Failed to parse OpenAI response: ' + err.message } }];
}
